                    statement.close();
                    assertTrue( underlyingStatement.isClosed() );
                }
            }
        }
    }

    @Test
    @DisplayName( "ResultSet leak" )
    @SuppressWarnings( "JDBCResourceOpenedButNotSafelyClosed" )
    void resultSetLeak() throws SQLException {
